const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

const filepath = typeof payload.filepath === 'string' ? payload.filepath.trim() : '';
const filename = typeof payload.filename === 'string' && payload.filename.trim()
  ? payload.filename.trim()
  : (filepath ? filepath.split('/').pop() : '');
const content = typeof payload.content === 'string' ? payload.content : '';
const modifiedEpoch = payload.modifiedEpoch !== undefined && payload.modifiedEpoch !== null
  ? Number(payload.modifiedEpoch)
  : null;

if (!filepath) {
  throw new Error('Missing filepath in webhook payload');
}

if (!filepath.startsWith('/')) {
  throw new Error(`Expected absolute filepath, got: ${filepath}`);
}

if (!filename) {
  throw new Error('Missing filename in webhook payload');
}

if (!content || !content.trim()) {
  throw new Error('Missing or empty content in webhook payload');
}

return [{
  json: {
    filepath,
    filename,
    content,
    modifiedEpoch,
    source: 'file_ingest',
    category: 'project_note',
    ingestedAt: new Date().toISOString()
  }
}];

const item = $input.first();
const data = item.json;

const chunkSize = 1200;
const overlap = 200;

const normalize = (text) => text.replace(/\r\n/g, '\n').replace(/\t/g, '  ').trim();

const text = normalize(data.content || '');
if (!text) {
  throw new Error('Content is empty after normalization');
}

const chunks = [];
let start = 0;

while (start < text.length) {
  let end = Math.min(start + chunkSize, text.length);

  if (end < text.length) {
    const windowStart = Math.max(start + Math.floor(chunkSize * 0.6), start);
    const boundarySlice = text.slice(windowStart, end);
    const breakCandidates = [
      boundarySlice.lastIndexOf('\n\n'),
      boundarySlice.lastIndexOf('\n'),
      boundarySlice.lastIndexOf('. '),
      boundarySlice.lastIndexOf(' ')
    ].filter((idx) => idx > 0);

    if (breakCandidates.length > 0) {
      end = windowStart + Math.max(...breakCandidates) + 1;
    }
  }

  const chunkText = text.slice(start, end).trim();
  if (chunkText) {
    chunks.push(chunkText);
  }

  if (end >= text.length) break;
  start = Math.max(end - overlap, start + 1);
}

if (chunks.length === 0) {
  throw new Error('Chunking produced zero chunks');
}

if (chunks.length > 200) {
  throw new Error(`Refusing to embed ${chunks.length} chunks in one run`);
}

return [{
  json: {
    ...data,
    totalChunks: chunks.length,
    chunks: chunks.map((chunkText, index) => ({
      chunkIndex: index + 1,
      totalChunks: chunks.length,
      title: `${data.filename} :: chunk ${String(index + 1).padStart(2, '0')}`,
      content: chunkText
    }))
  }
}];

const item = $input.first();
const { chunks, filepath, filename, modifiedEpoch, source, category, ingestedAt, totalChunks } = item.json;

if (!Array.isArray(chunks) || chunks.length === 0) {
  throw new Error('Missing chunks array');
}

return [{
  json: {
    filepath,
    filename,
    modifiedEpoch,
    source,
    category,
    ingestedAt,
    totalChunks,
    chunks,
    inputs: chunks.map(chunk => chunk.content)
  }
}];

const base = $('Build Embedding Batch Request').first().json;
const response = $json;

const embeddings = Array.isArray(response.embeddings)
  ? response.embeddings
  : (Array.isArray(response.embedding) ? [response.embedding] : null);

if (!Array.isArray(embeddings) || embeddings.length === 0) {
  throw new Error('Embedding response missing embeddings[]');
}

if (embeddings.length !== base.chunks.length) {
  throw new Error(`Embedding count mismatch: got ${embeddings.length}, expected ${base.chunks.length}`);
}

const escapeSql = (value) => String(value ?? '').replace(/'/g, "''");

const values = base.chunks.map((chunk, index) => {
  const embedding = embeddings[index];

  if (!Array.isArray(embedding) || embedding.length === 0) {
    throw new Error(`Embedding missing or invalid for chunk ${chunk.chunkIndex}`);
  }

  const metadata = {
    filename: base.filename,
    filepath: base.filepath,
    modified_epoch: base.modifiedEpoch,
    ingested_at: base.ingestedAt,
    chunk_index: chunk.chunkIndex,
    total_chunks: chunk.totalChunks
  };

  const title = escapeSql(chunk.title);
  const content = escapeSql(chunk.content);
  const source = escapeSql(base.source);
  const category = escapeSql(base.category);
  const metadataSql = `'${escapeSql(JSON.stringify(metadata))}'::jsonb`;
  const embeddingSql = `'[${embedding.join(',')}]'::vector`;

  return `(
    '${source}',
    '${category}',
    '${title}',
    '${content}',
    ARRAY['file_ingest','chunked']::text[],
    ${metadataSql},
    ${embeddingSql}
  )`;
});

const query = `
INSERT INTO memories (
  source,
  category,
  title,
  content,
  tags,
  metadata_json,
  embedding
)
VALUES
${values.join(',\n')}
RETURNING id, title, source, category, created_at;
`;

return [{
  json: {
    filepath: base.filepath,
    filename: base.filename,
    modifiedEpoch: base.modifiedEpoch,
    totalChunks: base.totalChunks,
    query
  }
}];

const inserted = $input.all();
const base = $('Prepare Insert Query').first().json;

return [{
  json: {
    success: true,
    filepath: base.filepath,
    filename: base.filename,
    modifiedEpoch: base.modifiedEpoch,
    insertedCount: inserted.length,
    totalChunks: base.totalChunks
  }
}];
